package service.impl; import service.PlayerCardService;import dao.PlayerCardDao;import dao.impl.PlayerCardDaoImpl;import model.PlayerCard;import java.util.*; public class PlayerCardServiceImpl implements PlayerCardService{PlayerCardDao dao=new PlayerCardDaoImpl(); public List<PlayerCard> findAll(){return dao.findAll();} public List<PlayerCard> search(String k){return dao.search(k);} public void save(PlayerCard c){if(c.id==0)dao.add(c);else dao.update(c);} public void delete(int id){dao.delete(id);} }
